class RBACSystem:
    def __init__(self):
        self.users = {}      # user_id -> set of roles
        self.roles = {}       # role_id -> set of permissions
        self.permissions = {
            'read': 1,
            'write': 2,
            'execute': 4
        }

    def assign_role(self, user_id, role_id):
        if user_id not in self.users:
            self.users[user_id] = set()
        self.users[user_id].add(role_id)

    def assign_permission(self, role_id, permission):
        if role_id not in self.roles:
            self.roles[role_id] = set()
        self.roles[role_id].add(permission)

    def check_access(self, user_id, required_permission):
        if user_id not in self.users:
            return False

        for role in self.users[user_id]:
            if role in self.roles:
                if required_permission in self.roles[role]:
                    return True
        return False

# Example usage
rbac = RBACSystem()
rbac.assign_permission('admin', 'read')
rbac.assign_permission('admin', 'write')
rbac.assign_permission('admin', 'execute')
rbac.assign_role('user1', 'admin')
print(rbac.check_access('user1', 'write'))  # True

#include <stdio.h>
#include <stdbool.h>

#define MAX_CAPABILITIES 10

typedef struct {
    char resource_id[50];
    bool can_read;
    bool can_write;
    bool can_execute;
} Capability;

typedef struct {
    int pid;
    Capability capabilities[MAX_CAPABILITIES];
    int cap_count;
} Process;

bool check_capability(Process *proc, char *resource_id, char op) {
    for (int i = 0; i < proc->cap_count; i++) {
        if (strcmp(proc->capabilities[i].resource_id, resource_id) == 0) {
            switch(op) {
                case 'r': return proc->capabilities[i].can_read;
                case 'w': return proc->capabilities[i].can_write;
                case 'x': return proc->capabilities[i].can_execute;
            }
        }
    }
    return false;
}

void add_capability(Process *proc, char *res_id, bool r, bool w, bool x) {
    if (proc->cap_count < MAX_CAPABILITIES) {
        strcpy(proc->capabilities[proc->cap_count].resource_id, res_id);
        proc->capabilities[proc->cap_count].can_read = r;
        proc->capabilities[proc->cap_count].can_write = w;
        proc->capabilities[proc->cap_count].can_execute = x;
        proc->cap_count++;
    }
}
